function (method) {
  // cache original method
  const original = arrayProto[method]
  def(arrayMethods, method, function mutator(...args) {
    const result = original.apply(this, args)
    const ob = this.__ob__
    let inserted
    switch (method) {
      case 'push':
      case 'unshift':
        inserted = args
        break
      case 'splice':
        inserted = args.slice(2)
        break
    }
    if (inserted) ob.observeArray(inserted)
    // notify change
    if (__DEV__) {
      ob.dep.notify({
        type: TriggerOpTypes.ARRAY_MUTATION,
        target: this,
        key: method
      })
    } else {
      ob.dep.notify()
    }
    return result
  })
}

render(h, { children, data, props }) {
  let transProps = props.transProps
  if (!isPlainObject(transProps)) {
    transProps = props.noFade ? NO_FADE_PROPS : FADE_PROPS
    if (props.appear) {
      // Default the appear classes to equal the enter classes
      transProps = {
        ...transProps,
        appear: true,
        appearClass: transProps.enterClass,
        appearActiveClass: transProps.enterActiveClass,
        appearToClass: transProps.enterToClass
      }
    }
  }
  transProps = {
    mode: props.mode,
    ...transProps,
    // We always need `css` true
    css: true
  }

  const dataCopy = { ...data }
  delete dataCopy.props
  return h(
    'transition',
    // Any transition event listeners will get merged here
    mergeData(dataCopy, { props: transProps }),
    children
  )
}

export function normalizeRecordProps(
  record: RouteRecordRaw
): Record<string, _RouteRecordProps> {
  const propsObject = {} as Record<string, _RouteRecordProps>
  // props does not exist on redirect records, but we can set false directly
  const props = record.props || false
  if ('component' in record) {
    propsObject.default = props
  } else {
    // NOTE: we could also allow a function to be applied to every component.
    // Would need user feedback for use cases
    for (const name in record.components)
      propsObject[name] = typeof props === 'object' ? props[name] : props
  }

  return propsObject
}

