dateDisabled() {
  // Returns a function for validating if a date is within range
  // We grab this variables first to ensure a new function ref
  // is generated when the props value changes
  // We do this as we need to trigger the calendar computed prop
  // to update when these props update
  const rangeFn = this.dateOutOfRange
  // Return the function ref
  return date => {
    // Handle both `YYYY-MM-DD` and `Date` objects
    date = parseYMD(date)
    const ymd = formatYMD(date)
    return !!(rangeFn(date) || this.computedDateDisabledFn(ymd, date))
  }
}

dropdownClasses() {
  const { block, split } = this
  return [
    this.directionClass,
    this.boundaryClass,
    {
      show: this.visible,
      // The 'btn-group' class is required in `split` mode for button alignment
      // It needs also to be applied when `block` is disabled to allow multiple
      // dropdowns to be aligned one line
      'btn-group': split || !block,
      // When `block` is enabled and we are in `split` mode the 'd-flex' class
      // needs to be applied to allow the buttons to stretch to full width
      'd-flex': block && split
    }
  ]
}

function calculateSliceStart() {
  const currentPage = props.modelValue;
  const chunkSize = props.maxSize;
  const currentChunkStart = sliceStart.value;
  const currentChunkEnd = currentChunkStart + chunkSize;
  if (currentPage > currentChunkEnd) {
    const lastChunkStart = props.totalPage - chunkSize;
    if (currentPage > lastChunkStart) {
      sliceStart.value = lastChunkStart;
    } else {
      sliceStart.value = currentPage - 1;
    }
  } else if (currentPage < currentChunkStart + 1) {
    if (currentPage > chunkSize) {
      sliceStart.value = currentPage - chunkSize;
    } else {
      sliceStart.value = 0;
    }
  }
}

export function resolveConstructorOptions(Ctor: typeof Component) {
  let options = Ctor.options
  if (Ctor.super) {
    const superOptions = resolveConstructorOptions(Ctor.super)
    const cachedSuperOptions = Ctor.superOptions
    if (superOptions !== cachedSuperOptions) {
      // super option changed,
      // need to resolve new options.
      Ctor.superOptions = superOptions
      // check if there are any late-modified/attached options (#4976)
      const modifiedOptions = resolveModifiedOptions(Ctor)
      // update base extend options
      if (modifiedOptions) {
        extend(Ctor.extendOptions, modifiedOptions)
      }
      options = Ctor.options = mergeOptions(superOptions, Ctor.extendOptions)
      if (options.name) {
        options.components[options.name] = Ctor
      }
    }
  }
  return options
}

context() {
  const { selectedYMD, activeYMD } = this
  const selectedDate = parseYMD(selectedYMD)
  const activeDate = parseYMD(activeYMD)
  return {
    // The current value of the `v-model`
    selectedYMD,
    selectedDate,
    selectedFormatted: selectedDate
      ? this.formatDateString(selectedDate)
      : this.labelNoDateSelected,
    // Which date cell is considered active due to navigation
    activeYMD,
    activeDate,
    activeFormatted: activeDate ? this.formatDateString(activeDate) : '',
    // `true` if the date is disabled (when using keyboard navigation)
    disabled: this.dateDisabled(activeDate),
    // Locales used in formatting dates
    locale: this.computedLocale,
    calendarLocale: this.calendarLocale,
    rtl: this.isRTL
  }
}

providerTriggerContext() {
  // Used to trigger the provider function via a watcher. Only the fields that
  // are needed for triggering a provider update are included. Note that the
  // regular this.context is sent to the provider during fetches though, as they
  // may need all the prop info.
  const ctx = {
    apiUrl: this.apiUrl,
    filter: null,
    sortBy: null,
    sortDesc: null,
    perPage: null,
    currentPage: null
  }
  if (!this.noProviderFiltering) {
    // Either a string, or could be an object or array.
    ctx.filter = this.localFilter
  }
  if (!this.noProviderSorting) {
    ctx.sortBy = this.localSortBy
    ctx.sortDesc = this.localSortDesc
  }
  if (!this.noProviderPaging) {
    ctx.perPage = this.perPage
    ctx.currentPage = this.currentPage
  }
  return clone(ctx)
}

export function createComponentInstanceForVnode(
  // we know it's MountedComponentVNode but flow doesn't
  vnode: any,
  // activeInstance in lifecycle state
  parent?: any
): Component {
  const options: InternalComponentOptions = {
    _isComponent: true,
    _parentVnode: vnode,
    parent
  }
  // check inline-template render functions
  const inlineTemplate = vnode.data.inlineTemplate
  if (isDef(inlineTemplate)) {
    options.render = inlineTemplate.render
    options.staticRenderFns = inlineTemplate.staticRenderFns
  }
  return new vnode.componentOptions.Ctor(options)
}

function canNeverBeRef(node: Node, userReactiveImport: string): boolean {
  if (isCallOf(node, userReactiveImport)) {
    return true
  }
  switch (node.type) {
    case 'UnaryExpression':
    case 'BinaryExpression':
    case 'ArrayExpression':
    case 'ObjectExpression':
    case 'FunctionExpression':
    case 'ArrowFunctionExpression':
    case 'UpdateExpression':
    case 'ClassExpression':
    case 'TaggedTemplateExpression':
      return true
    case 'SequenceExpression':
      return canNeverBeRef(
        node.expressions[node.expressions.length - 1],
        userReactiveImport
      )
    default:
      if (node.type.endsWith('Literal')) {
        return true
      }
      return false
  }
}

stepValue(direction) {
  // Sets a new incremented or decremented value, supporting optional wrapping
  // Direction is either +1 or -1 (or a multiple thereof)
  let value = this.localValue
  if (!this.disabled && !isNull(value)) {
    const step = this.computedStep * direction
    const min = this.computedMin
    const max = this.computedMax
    const multiplier = this.computedMultiplier
    const wrap = this.wrap
    // We ensure that the value steps like a native input
    value = mathRound((value - min) / step) * step + min + step
    // We ensure that precision is maintained (decimals)
    value = mathRound(value * multiplier) / multiplier
    // Handle if wrapping is enabled
    this.localValue =
      value > max ? (wrap ? min : max) : value < min ? (wrap ? max : min) : value
  }
}

filteredItems() {
  // Note the criteria is debounced and sanitized
  const { localItems: items, localFilter: criteria } = this

  // Resolve the filtering function, when requested
  // We prefer the provided filtering function and fallback to the internal one
  // When no filtering criteria is specified the filtering factories will return `null`
  const filterFn = this.localFiltering
    ? this.filterFnFactory(this.localFilterFn, criteria) ||
      this.defaultFilterFnFactory(criteria)
    : null

  // We only do local filtering when requested and there are records to filter
  return filterFn && items.length > 0 ? items.filter(filterFn) : items
}

private async setChecked(checked = true) {
  // typecast so we get type safety
  const element = this.element as unknown as HTMLInputElement
  const type = this.attributes().type

  if (type === 'radio' && !checked) {
    throw Error(
      `wrapper.setChecked() cannot be called with parameter false on a '<input type="radio" /> element.`
    )
  }

  // we do not want to trigger an event if the user
  // attempting set the same value twice
  // this is because in a browser setting checked = true when it is
  // already true is a no-op; no change event is triggered
  if (checked === element.checked) {
    return
  }

  element.checked = checked
  this.trigger('input')
  return this.trigger('change')
}

start() {
  this.started = true
  this.push(this.template.head(this.context))

  if (this.inject) {
    // inline server-rendered head meta information
    if (this.context.head) {
      this.push(this.context.head)
    }

    // inline preload/prefetch directives for initial/async chunks
    const links = this.renderer.renderResourceHints(this.context)
    if (links) {
      this.push(links)
    }

    // CSS files and inline server-rendered CSS collected by vue-style-loader
    const styles = this.renderer.renderStyles(this.context)
    if (styles) {
      this.push(styles)
    }
  }

  this.push(this.template.neck(this.context))
}

export function* generateModifiers(
	options: TemplateCodegenOptions,
	ctx: TemplateCodegenContext,
	prop: CompilerDOM.DirectiveNode,
	propertyName: string = 'modifiers',
): Generator<Code> {
	const { modifiers } = prop;
	if (!modifiers.length) {
		return;
	}
	const startOffset = modifiers[0]!.loc.start.offset - 1;
	const endOffset = modifiers.at(-1)!.loc.end.offset;
	const token = yield* startBoundary('template', startOffset, codeFeatures.verification);
	yield propertyName;
	yield endBoundary(token, endOffset);
	yield `: { `;
	for (const mod of modifiers) {
		yield* generateObjectProperty(
			options,
			ctx,
			mod.content,
			mod.loc.start.offset,
			codeFeatures.withoutHighlight,
		);
		yield `: true, `;
	}
	yield `}, `;
}

function* generateIdentifier(
	options: TemplateCodegenOptions,
	ctx: TemplateCodegenContext,
	prop: CompilerDOM.DirectiveNode,
): Generator<Code> {
	const rawName = 'v-' + prop.name;
	const startOffset = prop.loc.start.offset;
	const token = yield* startBoundary('template', startOffset, codeFeatures.verification);
	yield names.directives;
	yield `.`;
	yield* generateCamelized(
		rawName,
		'template',
		prop.loc.start.offset,
		{
			...codeFeatures.withoutHighlightAndCompletion,
			verification: options.vueCompilerOptions.checkUnknownDirectives && !isBuiltInDirective(prop.name),
		},
	);
	if (!isBuiltInDirective(prop.name)) {
		ctx.recordComponentAccess('template', camelize(rawName), prop.loc.start.offset);
	}
	yield endBoundary(token, startOffset + rawName.length);
}

computedStyle() {
  const styles = {
    // Setting `noResize` to true will disable the ability for the user to
    // manually resize the textarea. We also disable when in auto height mode
    resize: !this.computedRows || this.noResize ? 'none' : null
  }
  if (!this.computedRows) {
    // Conditionally set the computed CSS height when auto rows/height is enabled
    // We avoid setting the style to `null`, which can override user manual resize handle
    styles.height = this.heightInPx
    // We always add a vertical scrollbar to the textarea when auto-height is
    // enabled so that the computed height calculation returns a stable value
    styles.overflowY = 'scroll'
  }
  return styles
}

